    (SELECT sedentary_minutes FROM pa_active_minutes WHERE id = 'A4F_65060' AND DATE(ts) = '2022-05-30') > 
    (SELECT AVG(sedentary_minutes) FROM pa_active_minutes WHERE DATE(ts) = '2022-05-30') AS is_higher;

